parameters.jsCode:
const cd = $variables.containerData || {containerId: 'unknown', containerName: 'unknown', ports: {}};
const port = cd.ports && typeof cd.ports === 'object' ? Object.keys(cd.ports)[0] : '8080';
return {system: 'traefik', status: 'pending', message: 'Traefik queued: ' + cd.containerName, port: port};

const cd = $variables.containerData || {containerName: 'unknown', metricsPort: 9090};
const jobName = 'auto-' + cd.containerName;
return {system: 'prometheus', status: 'pending', jobName: jobName, metricsPort: cd.metricsPort, message: 'Prometheus job: ' + jobName};

const cd = $variables.containerData || {containerName: 'unknown'};
const domain = cd.containerName + '.local';
return {system: 'kuma', status: 'pending', monitorName: cd.containerName + ' Uptime', url: 'https://' + domain, message: 'Uptime Kuma queued'};

const cd = $variables.containerData || {labels: {}};
const enabled = cd.labels['wireguard.enabled'] === 'true';
return {system: 'wireguard', status: enabled ? 'pending' : 'skipped', message: enabled ? 'WireGuard peer config queued' : 'WireGuard skipped'};

